{
  "name": "STP-AI Sludge Robot Control Center",
  "description": "An advanced AI-assisted dashboard for remotely monitoring and controlling sludge removal robots in sewage treatment plants, featuring real-time gas risk prediction, sludge density analysis, and intelligent cleaning guidance.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum SludgeLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HEAVY = 'HEAVY'
}

export enum RiskLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH'
}

export interface SensorData {
  h2s: number; // hydrogen sulfide in ppm
  methane: number; // ppm
  motorCurrent: number; // Amps
  tilt: { x: number; y: number; z: number };
  timestamp: number;
}

export interface AIAnalysis {
  sludgeLevel: SludgeLevel;
  gasRisk: RiskLevel;
  isStuck: boolean;
  recommendation: string;
  targetZone?: string;
}

export interface RobotStatus {
  connected: boolean;
  cleaning: boolean;
  brushSpeed: number;
  pumpActive: boolean;
  direction: 'forward' | 'backward' | 'left' | 'right' | 'stop';
}

import { GoogleGenAI, Type } from "@google/genai";
import { SludgeLevel, RiskLevel, AIAnalysis, SensorData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzeRobotState(
  imageBytes: string | null,
  sensors: SensorData[]
): Promise<AIAnalysis> {
  const model = "gemini-3-flash-preview";

  const sensorContext = sensors.slice(-10).map(s => ({
    h2s: s.h2s,
    ch4: s.methane,
    current: s.motorCurrent,
    tilt: s.tilt
  }));

  const prompt = `
    Analyze the STP sludge removal robot's current environment.
    Visual Data: Current camera frame from the sewage tank.
    Sensor History (last 10 ticks): ${JSON.stringify(sensorContext)}

    Tasks:
    1. Detect sludge density from the image (LOW, MEDIUM, HEAVY).
    2. Predict gas risk level based on H2S and CH4 trends.
    3. Detect if robot is stuck (compare high motor current vs no change in IMU/tilt).
    4. Provide a cleaning recommendation.
    5. Identify the best zone to move towards.
  `;

  const contents: any[] = [{ text: prompt }];

  if (imageBytes) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageBytes
      }
    });
  }

  const response = await ai.models.generateContent({
    model,
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sludgeLevel: { type: Type.STRING, enum: Object.values(SludgeLevel) },
          gasRisk: { type: Type.STRING, enum: Object.values(RiskLevel) },
          isStuck: { type: Type.BOOLEAN },
          recommendation: { type: Type.STRING },
          targetZone: { type: Type.STRING }
        },
        required: ["sludgeLevel", "gasRisk", "isStuck", "recommendation"]
      }
    }
  });

  return JSON.parse(response.text || "{}") as AIAnalysis;
}

