import React, { useRef, useEffect, useState } from 'react';

interface CameraFeedProps {
  onCapture: (base64: string) => void;
}

export const CameraFeed: React.FC<CameraFeedProps> = ({ onCapture }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [devices, setDevices] = useState<MediaDeviceInfo[]>([]);
  const [selectedDevice, setSelectedDevice] = useState<string>('');

  useEffect(() => {
    async function getDevices() {
      const allDevices = await navigator.mediaDevices.enumerateDevices();
      const videoDevices = allDevices.filter(d => d.kind === 'videoinput');
      setDevices(videoDevices);
      if (videoDevices.length > 0) setSelectedDevice(videoDevices[0].deviceId);
    }
    getDevices();
  }, []);

  useEffect(() => {
    if (!selectedDevice) return;

    let stream: MediaStream | null = null;
    async function startCamera() {
      try {
        stream = await navigator.mediaDevices.getUserMedia({
          video: { deviceId: selectedDevice, width: 640, height: 480 }
        });
        if (videoRef.current) videoRef.current.srcObject = stream;
      } catch (err) {
        console.error("Camera access error:", err);
      }
    }
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, [selectedDevice]);

  const captureFrame = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        context.drawImage(videoRef.current, 0, 0, 640, 480);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);
        onCapture(dataUrl.split(',')[1]);
      }
    }
  };

  useEffect(() => {
    const interval = setInterval(captureFrame, 5000); // Auto capture every 5s for AI
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="bg-black rounded-xl overflow-hidden relative border border-gray-700 shadow-2xl group">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className="w-full aspect-video object-cover"
      />
      <canvas ref={canvasRef} width={640} height={480} className="hidden" />

      <div className="absolute top-4 left-4 bg-gray-900/80 px-3 py-1.5 rounded-md text-xs font-mono border border-gray-700 backdrop-blur-sm">
        CAM_01: EXTERNAL_FEED
      </div>

      <div className="absolute bottom-4 right-4 flex space-x-2">
        <select 
          className="bg-gray-900/80 border border-gray-700 text-xs px-2 py-1 rounded outline-none"
          value={selectedDevice}
          onChange={(e) => setSelectedDevice(e.target.value)}
        >
          {devices.map(d => (
            <option key={d.deviceId} value={d.deviceId}>{d.label || `Camera ${d.deviceId.slice(0,4)}`}</option>
          ))}
        </select>
        <button 
          onClick={captureFrame}
          className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-1 rounded text-xs transition-colors"
        >
          MANUAL_SCAN
        </button>
      </div>

      {/* Decorative Overlays */}
      <div className="absolute inset-0 pointer-events-none border-4 border-emerald-500/10 opacity-50 group-hover:opacity-100 transition-opacity"></div>
      <div className="absolute top-1/2 left-0 w-full h-[1px] bg-emerald-500/20 shadow-[0_0_10px_emerald]"></div>
    </div>
  );
};

import React from 'react';
import { SensorData, RiskLevel } from '../types';

interface SensorGridProps {
  data: SensorData;
  gasRisk: RiskLevel;
}

export const SensorGrid: React.FC<SensorGridProps> = ({ data, gasRisk }) => {
  const getRiskColor = (level: RiskLevel) => {
    switch (level) {
      case RiskLevel.HIGH: return 'text-red-500';
      case RiskLevel.MEDIUM: return 'text-amber-500';
      default: return 'text-emerald-500';
    }
  };

  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
      <StatCard 
        label="H₂S Level" 
        value={`${data.h2s.toFixed(1)} ppm`} 
        status={data.h2s > 10 ? 'warning' : 'ok'}
      />
      <StatCard 
        label="Methane (CH₄)" 
        value={`${data.methane.toFixed(1)} ppm`} 
        status={data.methane > 50 ? 'warning' : 'ok'}
      />
      <StatCard 
        label="Motor Current" 
        value={`${data.motorCurrent.toFixed(2)} A`} 
        status={data.motorCurrent > 1.5 ? 'critical' : 'ok'}
      />
      <StatCard 
        label="AI Risk Index" 
        value={gasRisk} 
        customColor={getRiskColor(gasRisk)}
      />
    </div>
  );
};

const StatCard: React.FC<{ 
  label: string; 
  value: string; 
  status?: 'ok' | 'warning' | 'critical'; 
  customColor?: string;
}> = ({ label, value, status, customColor }) => {
  const colorClass = customColor || (
    status === 'critical' ? 'text-red-500' :
    status === 'warning' ? 'text-amber-500' :
    'text-emerald-500'
  );

  return (
    <div className="bg-gray-800 border border-gray-700 p-4 rounded-xl shadow-lg">
      <div className="text-gray-400 text-xs font-semibold uppercase tracking-wider mb-1">{label}</div>
      <div className={`text-2xl font-bold font-mono ${colorClass}`}>
        {value}
      </div>
    </div>
  );
};

import React from 'react';
import { RobotStatus } from '../types';

interface RobotControlsProps {
  status: RobotStatus;
  onCommand: (cmd: Partial<RobotStatus>) => void;
}

export const RobotControls: React.FC<RobotControlsProps> = ({ status, onCommand }) => {
  const directions = [
    { label: '↖', val: 'left' as const },
    { label: '↑', val: 'forward' as const },
    { label: '↗', val: 'right' as const },
    { label: '←', val: 'left' as const },
    { label: 'STOP', val: 'stop' as const, color: 'bg-red-600 hover:bg-red-500' },
    { label: '→', val: 'right' as const },
    { label: '↙', val: 'backward' as const },
    { label: '↓', val: 'backward' as const },
    { label: '↘', val: 'backward' as const },
  ];

  return (
    <div className="bg-gray-800 border border-gray-700 rounded-xl p-6 shadow-xl">
      <h3 className="text-sm font-bold uppercase text-gray-400 mb-6 flex items-center">
        <span className="w-2 h-2 bg-emerald-500 rounded-full mr-2"></span>
        Robot Tactical Controls
      </h3>

      <div className="grid grid-cols-3 gap-2 max-w-[200px] mx-auto mb-8">
        {directions.map((d, i) => (
          <button
            key={i}
            onClick={() => onCommand({ direction: d.val })}
            className={`p-4 rounded-lg font-bold transition-all transform active:scale-95 ${
              status.direction === d.val && d.val !== 'stop' ? 'ring-2 ring-emerald-500 bg-gray-700' : 
              d.color || 'bg-gray-700 hover:bg-gray-600'
            }`}
          >
            {d.label}
          </button>
        ))}
      </div>

      <div className="space-y-4">
        <div className="flex justify-between items-center">
          <span className="text-sm text-gray-400">Brush System</span>
          <button 
            onClick={() => onCommand({ cleaning: !status.cleaning })}
            className={`px-4 py-1.5 rounded-full text-xs font-bold transition-colors ${
              status.cleaning ? 'bg-emerald-600 text-white' : 'bg-gray-700 text-gray-400'
            }`}
          >
            {status.cleaning ? 'ACTIVE' : 'IDLE'}
          </button>
        </div>

        <div className="flex justify-between items-center">
          <span className="text-sm text-gray-400">Pump Power</span>
          <button 
            onClick={() => onCommand({ pumpActive: !status.pumpActive })}
            className={`px-4 py-1.5 rounded-full text-xs font-bold transition-colors ${
              status.pumpActive ? 'bg-blue-600 text-white' : 'bg-gray-700 text-gray-400'
            }`}
          >
            {status.pumpActive ? 'EXTRACTING' : 'OFF'}
          </button>
        </div>

        <div>
          <div className="flex justify-between text-xs text-gray-500 mb-2">
            <span>RPM CONTROL</span>
            <span>{status.brushSpeed}%</span>
          </div>
          <input 
            type="range" 
            min="0" max="100" 
            value={status.brushSpeed}
            onChange={(e) => onCommand({ brushSpeed: parseInt(e.target.value) })}
            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-emerald-500" 
          />
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { DashboardHeader } from './components/DashboardHeader';
import { CameraFeed } from './components/CameraFeed';
import { SensorGrid } from './components/SensorGrid';
import { RobotControls } from './components/RobotControls';
import { analyzeRobotState } from './services/geminiService';
import { SensorData, RobotStatus, AIAnalysis, SludgeLevel, RiskLevel } from './types';

const App: React.FC = () => {
  const [sensors, setSensors] = useState<SensorData[]>([]);
  const [robotStatus, setRobotStatus] = useState<RobotStatus>({
    connected: true,
    cleaning: false,
    brushSpeed: 30,
    pumpActive: false,
    direction: 'stop'
  });
  const [aiResult, setAiResult] = useState<AIAnalysis>({
    sludgeLevel: SludgeLevel.LOW,
    gasRisk: RiskLevel.LOW,
    isStuck: false,
    recommendation: "System initializing. Awaiting camera link.",
    targetZone: "N/A"
  });
  const [logs, setLogs] = useState<{msg: string, type: 'info'|'warn'|'err'}[]>([]);

  // Simulate sensor data stream
  useEffect(() => {
    const interval = setInterval(() => {
      setSensors(prev => {
        const last = prev[prev.length - 1] || { 
          h2s: 5, methane: 10, motorCurrent: 0.8, 
          tilt: {x: 0, y: 0, z: 9.8}, timestamp: Date.now() 
        };

        // Add random jitter
        const newData: SensorData = {
          h2s: Math.max(0, last.h2s + (Math.random() - 0.5) * 0.5),
          methane: Math.max(0, last.methane + (Math.random() - 0.5) * 2),
          motorCurrent: robotStatus.cleaning ? 1.2 + (Math.random() - 0.5) * 0.4 : 0.8 + (Math.random() - 0.5) * 0.1,
          tilt: {
            x: last.tilt.x + (Math.random() - 0.5) * 0.1,
            y: last.tilt.y + (Math.random() - 0.5) * 0.1,
            z: 9.8 + (Math.random() - 0.5) * 0.2
          },
          timestamp: Date.now()
        };
        return [...prev.slice(-19), newData];
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [robotStatus.cleaning]);

  const handleCapture = async (base64: string) => {
    try {
      const result = await analyzeRobotState(base64, sensors);
      setAiResult(result);

      if (result.isStuck) {
        setLogs(prev => [{ msg: "ALERT: Robot collision or stall detected!", type: 'err' }, ...prev]);
      }
    } catch (err) {
      console.error("AI Analysis failed:", err);
    }
  };

  const addLog = (msg: string, type: 'info'|'warn'|'err' = 'info') => {
    setLogs(prev => [{ msg: `[${new Date().toLocaleTimeString()}] ${msg}`, type }, ...prev.slice(0, 49)]);
  };

  const handleCommand = (cmd: Partial<RobotStatus>) => {
    setRobotStatus(prev => ({ ...prev, ...cmd }));
    if (cmd.direction) addLog(`Command issued: MOVE_${cmd.direction.toUpperCase()}`);
    if (cmd.cleaning !== undefined) addLog(`Cleaning system: ${cmd.cleaning ? 'ENABLED' : 'DISABLED'}`);
  };

  const latestSensor = sensors[sensors.length - 1] || { 
    h2s: 0, methane: 0, motorCurrent: 0, tilt: {x:0,y:0,z:0}, timestamp: 0 
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-gray-950 font-sans selection:bg-emerald-500/30">
      <DashboardHeader isConnected={robotStatus.connected} />

      <main className="flex-1 flex overflow-hidden p-6 gap-6">
        {/* Left Side: Feed and Sensors */}
        <div className="flex-[2] flex flex-col gap-6 overflow-y-auto pr-2">
          <CameraFeed onCapture={handleCapture} />
          <SensorGrid data={latestSensor} gasRisk={aiResult.gasRisk} />

          <div className="bg-gray-900 border border-gray-800 rounded-xl p-6 flex-1 shadow-inner">
            <h3 className="text-sm font-bold uppercase text-gray-500 mb-4 flex justify-between items-center">
              <span>AI Decision Reasoning</span>
              <span className="text-xs bg-gray-800 px-2 py-0.5 rounded text-emerald-500">GEMINI_FLASH_AUTO</span>
            </h3>
            <div className="space-y-4">
              <div className="flex items-start space-x-4">
                <div className={`p-2 rounded-lg ${aiResult.isStuck ? 'bg-red-900/40' : 'bg-emerald-900/40'}`}>
                   {aiResult.isStuck ? (
                     <svg className="w-6 h-6 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                   ) : (
                     <svg className="w-6 h-6 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                   )}
                </div>
                <div>
                  <h4 className="font-bold text-gray-200">Robot Recommendation</h4>
                  <p className="text-gray-400 text-sm leading-relaxed">{aiResult.recommendation}</p>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 mt-6">
                <div className="bg-gray-800/50 p-4 rounded-lg border border-gray-700">
                  <span className="text-xs text-gray-500 block mb-1">Sludge Density</span>
                  <span className={`text-lg font-bold ${
                    aiResult.sludgeLevel === SludgeLevel.HEAVY ? 'text-red-400' :
                    aiResult.sludgeLevel === SludgeLevel.MEDIUM ? 'text-amber-400' :
                    'text-emerald-400'
                  }`}>{aiResult.sludgeLevel}</span>
                </div>
                <div className="bg-gray-800/50 p-4 rounded-lg border border-gray-700">
                  <span className="text-xs text-gray-500 block mb-1">Target Zone</span>
                  <span className="text-lg font-bold text-blue-400 uppercase">{aiResult.targetZone}</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right Side: Controls and Logs */}
        <div className="flex-1 flex flex-col gap-6 max-w-sm">
          <RobotControls status={robotStatus} onCommand={handleCommand} />

          <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 flex-1 flex flex-col shadow-inner overflow-hidden">
            <h3 className="text-xs font-bold uppercase text-gray-500 mb-3 tracking-tighter">System Telemetry Logs</h3>
            <div className="flex-1 overflow-y-auto font-mono text-[10px] space-y-1.5 scrollbar-thin scrollbar-thumb-gray-700">
              {logs.length === 0 && <div className="text-gray-700 italic">No activity logs...</div>}
              {logs.map((log, i) => (
                <div key={i} className={`p-1.5 rounded border-l-2 ${
                  log.type === 'err' ? 'bg-red-900/20 border-red-500 text-red-200' :
                  log.type === 'warn' ? 'bg-amber-900/20 border-amber-500 text-amber-200' :
                  'bg-gray-800/40 border-gray-600 text-gray-400'
                }`}>
                  {log.msg}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="bg-gray-900 border-t border-gray-800 px-6 py-2 text-[10px] text-gray-600 flex justify-between">
        <div className="flex space-x-4">
          <span>LAT: 12.9716° N</span>
          <span>LNG: 77.5946° E</span>
          <span>ESP32_V3_FW_1.2.4</span>
        </div>
        <div className="uppercase font-bold tracking-widest text-emerald-900">
          Operation SludgeForce-2024
        </div>
      </footer>
    </div>
  );
};

export default App;

export enum SludgeLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HEAVY = 'HEAVY'
}

export enum RiskLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH'
}

export interface SensorData {
  h2s: number; // hydrogen sulfide in ppm
  methane: number; // ppm
  motorCurrent: number; // Amps
  tilt: { x: number; y: number; z: number };
  timestamp: number;
}

export interface AIAnalysis {
  sludgeLevel: SludgeLevel;
  gasRisk: RiskLevel;
  isStuck: boolean;
  recommendation: string;
  targetZone?: string;
}

export interface RobotStatus {
  connected: boolean;
  cleaning: boolean;
  brushSpeed: number;
  pumpActive: boolean;
  direction: 'forward' | 'backward' | 'left' | 'right' | 'stop';
  eStopActive: boolean;
}

export interface SafetyConfig {
  h2sLimit: number;
  methaneLimit: number;
  maxCurrent: number;
  tiltLimit: number;
}

export const DEFAULT_SAFETY_CONFIG: SafetyConfig = {
  h2sLimit: 15.0,
  methaneLimit: 100.0,
  maxCurrent: 2.0,
  tiltLimit: 30.0,
};

import React, { useState, useEffect } from 'react';

interface HeaderProps {
  isConnected: boolean;
  isDemoMode: boolean;
  eStopActive: boolean;
  onToggleDemo: () => void;
  onEStop: () => void;
}

export const DashboardHeader: React.FC<HeaderProps> = ({ 
  isConnected, 
  isDemoMode, 
  eStopActive, 
  onToggleDemo, 
  onEStop 
}) => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <header className="bg-gray-800 border-b border-gray-700 px-6 py-4 flex justify-between items-center sticky top-0 z-50">
      <div className="flex items-center space-x-4">
        <div className="p-2 bg-emerald-600 rounded-lg">
          <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
