          </svg>
        </div>
        <div>
          <h1 className="text-xl font-bold tracking-tight leading-none">STP-AI <span className="text-emerald-500">SludgeForce</span></h1>
          <span className="text-[10px] text-gray-500 font-mono tracking-widest uppercase">Safety Tier: Mission Critical</span>
        </div>
      </div>

      <div className="flex items-center space-x-6">
        <div className="flex items-center space-x-4 mr-4">
          <button 
            onClick={onToggleDemo}
            className={`px-3 py-1 rounded-md text-[10px] font-bold border transition-colors ${
