import React, { useRef, useEffect, useState } from 'react';

interface CameraFeedProps {
  onCapture: (base64: string) => void;
  isSimulated: boolean;
}

interface SimulatedScenario {
  id: string;
  label: string;
  url: string;
}

const SCENARIOS: SimulatedScenario[] = [
  { 
    id: 'low', 
    label: 'Low Sludge (Clear Flow)', 
    url: 'https://assets.mixkit.co/videos/preview/mixkit-water-flowing-in-a-treatment-plant-39844-large.mp4' 
  },
  { 
    id: 'medium', 
    label: 'Medium Sludge (Active Mixing)', 
    url: 'https://assets.mixkit.co/videos/preview/mixkit-sewage-water-flowing-in-a-treatment-plant-39845-large.mp4' 
  },
  { 
    id: 'heavy', 
    label: 'Heavy Sludge (Industrial)', 
    url: 'https://assets.mixkit.co/videos/preview/mixkit-thick-muddy-water-flowing-down-a-river-42866-large.mp4' 
  }
];

export const CameraFeed: React.FC<CameraFeedProps> = ({ onCapture, isSimulated }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const simVideoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [devices, setDevices] = useState<MediaDeviceInfo[]>([]);
  const [selectedDevice, setSelectedDevice] = useState<string>('');
  const [cameraActive, setCameraActive] = useState(false);
  const [currentScenario, setCurrentScenario] = useState<SimulatedScenario>(SCENARIOS[1]);

  useEffect(() => {
    async function getDevices() {
      try {
        const allDevices = await navigator.mediaDevices.enumerateDevices();
        const videoDevices = allDevices.filter(d => d.kind === 'videoinput');
        setDevices(videoDevices);
        if (videoDevices.length > 0) setSelectedDevice(videoDevices[0].deviceId);
      } catch (err) {
        console.warn("Could not list devices", err);
      }
    }
    getDevices();
  }, []);

  useEffect(() => {
    if (!selectedDevice || isSimulated) {
      setCameraActive(false);
      return;
    }

    let stream: MediaStream | null = null;
    async function startCamera() {
      try {
        stream = await navigator.mediaDevices.getUserMedia({
          video: { deviceId: selectedDevice, width: 640, height: 480 }
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          setCameraActive(true);
        }
      } catch (err) {
        console.error("Camera access error:", err);
        setCameraActive(false);
      }
    }
    startCamera();
    return () => stream?.getTracks().forEach(t => t.stop());
  }, [selectedDevice, isSimulated]);

  const captureFrame = () => {
    if (canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (!context) return;

      if (cameraActive && videoRef.current && !isSimulated) {
        context.drawImage(videoRef.current, 0, 0, 640, 480);
      } else if (simVideoRef.current) {
        context.drawImage(simVideoRef.current, 0, 0, 640, 480);
        // Overlay HUD text for AI context
        context.fillStyle = 'rgba(16, 185, 129, 0.2)';
        context.fillRect(0, 0, 640, 40);
        context.font = 'bold 14px monospace';
        context.fillStyle = '#10b981';
        context.fillText(`SIM_SOURCE: ${currentScenario.label.toUpperCase()}`, 15, 25);
        context.font = '10px monospace';
        context.fillText(`ISO: 800 | FPS: 30.0 | TEMP: 24°C`, 450, 25);
      }

      const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);
      onCapture(dataUrl.split(',')[1]);
    }
  };

  useEffect(() => {
    const interval = setInterval(captureFrame, 5000);
    return () => clearInterval(interval);
  }, [cameraActive, isSimulated, currentScenario]);

  return (
    <div className="bg-black rounded-xl overflow-hidden relative border border-gray-700 shadow-2xl group">
      {/* Real Video Feed */}
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className={`w-full aspect-video object-cover ${(cameraActive && !isSimulated) ? 'block' : 'hidden'}`}
      />

      {/* Simulated Feed / Video Loops */}
      {(!cameraActive || isSimulated) && (
        <div className="relative w-full aspect-video bg-gray-900 flex items-center justify-center overflow-hidden">
           <video 
            ref={simVideoRef}
            src={currentScenario.url} 
            autoPlay 
            muted 
            loop 
            playsInline
            className="absolute inset-0 w-full h-full object-cover opacity-70 grayscale contrast-125"
          />

          {/* Simulation Overlay */}
          <div className="z-10 pointer-events-none text-center">
            <div className="inline-block animate-pulse mb-2 px-3 py-1 bg-emerald-600/20 border border-emerald-500 rounded text-emerald-500 text-[10px] font-bold uppercase tracking-widest">
              AI Simulation Stream
            </div>
            <p className="text-gray-400 text-[10px] font-mono opacity-50">NODE_ID: SLUDGE_BOT_SIM_001</p>
          </div>

          {/* Source Switcher for Demo */}
          <div className="absolute top-14 right-4 flex flex-col space-y-1 z-20">
            {SCENARIOS.map(s => (
              <button 
                key={s.id}
                onClick={() => setCurrentScenario(s)}
                className={`px-2 py-1 text-[9px] font-bold rounded border transition-all ${
                  currentScenario.id === s.id 
                  ? 'bg-emerald-600 border-emerald-400 text-white' 
                  : 'bg-gray-800/80 border-gray-700 text-gray-400 hover:bg-gray-700'
                }`}
              >
                {s.id.toUpperCase()}
              </button>
            ))}
          </div>

          {/* Scanline and Vignette Effect */}
          <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.1)_50%),linear-gradient(90deg,rgba(255,0,0,0.03),rgba(0,255,0,0.01),rgba(0,0,255,0.03))] bg-[length:100%_3px,3px_100%]"></div>
          <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_100px_rgba(0,0,0,0.8)]"></div>
        </div>
      )}

      <canvas ref={canvasRef} width={640} height={480} className="hidden" />

      <div className="absolute top-4 left-4 bg-gray-900/80 px-3 py-1.5 rounded-md text-xs font-mono border border-gray-700 backdrop-blur-sm flex items-center space-x-2 z-20">
        <span className={`w-2 h-2 rounded-full ${cameraActive && !isSimulated ? 'bg-emerald-500 animate-pulse' : 'bg-amber-500'}`}></span>
        <span>{cameraActive && !isSimulated ? 'LIVE_CAM_FEED' : 'VIRTUAL_SENSOR_STREAM'}</span>
      </div>

      <div className="absolute bottom-4 right-4 flex space-x-2 z-20">
        {!isSimulated && devices.length > 0 && (
          <select 
            className="bg-gray-900/80 border border-gray-700 text-xs px-2 py-1 rounded outline-none text-gray-300"
            value={selectedDevice}
            onChange={(e) => setSelectedDevice(e.target.value)}
          >
            {devices.map(d => (
              <option key={d.deviceId} value={d.deviceId}>{d.label || `Camera ${d.deviceId.slice(0,4)}`}</option>
            ))}
          </select>
        )}
        <button 
          onClick={captureFrame}
          className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-1 rounded text-xs font-bold transition-colors shadow-lg active:scale-95"
        >
          ANALYSIS_SYNC
        </button>
      </div>

      <div className="absolute inset-0 pointer-events-none border border-emerald-500/10 group-hover:border-emerald-500/20 transition-all"></div>
    </div>
  );
};

export enum SludgeLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HEAVY = 'HEAVY'
}

export enum RiskLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH'
}

export interface SensorData {
  h2s: number; // hydrogen sulfide in ppm
  methane: number; // ppm
  motorCurrent: number; // Amps
  tilt: { x: number; y: number; z: number };
  timestamp: number;
  battery: number; // Percentage 0-100
  isOffline: boolean; // Simulator flag for sensor failure
}

export interface AIAnalysis {
  sludgeLevel: SludgeLevel;
  gasRisk: RiskLevel;
  isStuck: boolean;
  recommendation: string;
  targetZone?: string;
}

export interface RobotStatus {
  connected: boolean;
  cleaning: boolean;
  brushSpeed: number;
  pumpActive: boolean;
  direction: 'forward' | 'backward' | 'left' | 'right' | 'stop';
  eStopActive: boolean;
}

export interface SafetyConfig {
  h2sLimit: number;
  methaneLimit: number;
  maxCurrent: number;
  tiltLimit: number;
  batteryCritical: number;
}

export const DEFAULT_SAFETY_CONFIG: SafetyConfig = {
  h2sLimit: 15.0,
  methaneLimit: 100.0,
  maxCurrent: 2.0,
  tiltLimit: 30.0,
  batteryCritical: 15.0,
};

import { GoogleGenAI, Type } from "@google/genai";
import { SludgeLevel, RiskLevel, AIAnalysis, SensorData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzeRobotState(
  imageBytes: string | null,
  sensors: SensorData[]
): Promise<AIAnalysis> {
  const model = "gemini-3-flash-preview";

  const sensorContext = sensors.slice(-10).map(s => ({
    h2s: s.isOffline ? 'OFFLINE' : s.h2s,
    ch4: s.isOffline ? 'OFFLINE' : s.methane,
    current: s.motorCurrent,
    tilt: s.tilt,
    battery: s.battery
  }));

  const prompt = `
    Analyze the STP sludge removal robot's current environment.
    Visual Data: Current camera frame from the sewage tank.
    Sensor History (last 10 ticks): ${JSON.stringify(sensorContext)}

    Tasks:
    1. Detect sludge density from the image (LOW, MEDIUM, HEAVY).
    2. Predict gas risk level based on H2S and CH4 trends.
    3. Detect if robot is stuck (compare high motor current vs no change in IMU/tilt).
    4. Provide a cleaning recommendation. Consider battery level (recharge if < 20%) and sensor health.
    5. Identify the best zone to move towards.
  `;

  const contents: any[] = [{ text: prompt }];

  if (imageBytes) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: imageBytes
      }
    });
  }

  const response = await ai.models.generateContent({
    model,
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sludgeLevel: { type: Type.STRING, enum: Object.values(SludgeLevel) },
          gasRisk: { type: Type.STRING, enum: Object.values(RiskLevel) },
          isStuck: { type: Type.BOOLEAN },
          recommendation: { type: Type.STRING },
          targetZone: { type: Type.STRING }
        },
        required: ["sludgeLevel", "gasRisk", "isStuck", "recommendation"]
      }
    }
  });

  return JSON.parse(response.text || "{}") as AIAnalysis;
}

import React from 'react';
import { SensorData, RiskLevel } from '../types';

interface SensorGridProps {
  data: SensorData;
  gasRisk: RiskLevel;
}

export const SensorGrid: React.FC<SensorGridProps> = ({ data, gasRisk }) => {
  const getRiskColor = (level: RiskLevel) => {
    switch (level) {
      case RiskLevel.HIGH: return 'text-red-500';
      case RiskLevel.MEDIUM: return 'text-amber-500';
      default: return 'text-emerald-500';
    }
  };

  return (
    <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
      <StatCard 
        label="H₂S Level" 
        value={data.isOffline ? 'ERR' : `${data.h2s.toFixed(1)} ppm`} 
        status={data.isOffline ? 'critical' : data.h2s > 10 ? 'warning' : 'ok'}
      />
      <StatCard 
        label="Methane (CH₄)" 
        value={data.isOffline ? 'ERR' : `${data.methane.toFixed(1)} ppm`} 
        status={data.isOffline ? 'critical' : data.methane > 50 ? 'warning' : 'ok'}
      />
      <StatCard 
        label="Motor Current" 
        value={`${data.motorCurrent.toFixed(2)} A`} 
        status={data.motorCurrent > 2.0 ? 'critical' : 'ok'}
      />
      <StatCard 
        label="Battery" 
        value={`${Math.round(data.battery)}%`} 
        status={data.battery < 20 ? 'critical' : data.battery < 40 ? 'warning' : 'ok'}
      />
      <StatCard 
        label="AI Risk" 
        value={gasRisk} 
        customColor={getRiskColor(gasRisk)}
      />
    </div>
  );
};

const StatCard: React.FC<{ 
  label: string; 
  value: string; 
  status?: 'ok' | 'warning' | 'critical'; 
  customColor?: string;
}> = ({ label, value, status, customColor }) => {
  const colorClass = customColor || (
    status === 'critical' ? 'text-red-500' :
    status === 'warning' ? 'text-amber-500' :
    'text-emerald-500'
  );

  return (
    <div className="bg-gray-800 border border-gray-700 p-4 rounded-xl shadow-lg">
      <div className="text-gray-400 text-[10px] font-semibold uppercase tracking-wider mb-1">{label}</div>
      <div className={`text-xl font-bold font-mono ${colorClass}`}>
        {value}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { DashboardHeader } from './components/DashboardHeader';
import { CameraFeed } from './components/CameraFeed';
import { SensorGrid } from './components/SensorGrid';
import { RobotControls } from './components/RobotControls';
import { DemoPanel } from './components/DemoPanel';
import { SafetyStatus } from './components/SafetyStatus';
import { analyzeRobotState } from './services/geminiService';
import { 
  SensorData, RobotStatus, AIAnalysis, 
  SludgeLevel, RiskLevel, DEFAULT_SAFETY_CONFIG 
} from './types';

const App: React.FC = () => {
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [sensors, setSensors] = useState<SensorData[]>([]);
  const [robotStatus, setRobotStatus] = useState<RobotStatus>({
    connected: true,
    cleaning: false,
    brushSpeed: 30,
    pumpActive: false,
    direction: 'stop',
    eStopActive: false
  });
  const [aiResult, setAiResult] = useState<AIAnalysis>({
    sludgeLevel: SludgeLevel.LOW,
    gasRisk: RiskLevel.LOW,
    isStuck: false,
    recommendation: "System initializing. Monitoring environment.",
    targetZone: "N/A"
  });
  const [logs, setLogs] = useState<{msg: string, type: 'info'|'warn'|'err'}[]>([]);

  const safetyConfig = DEFAULT_SAFETY_CONFIG;
  const isOverriddenBySafety = useRef(false);

  // Safety logic check
  const latestSensor = sensors[sensors.length - 1] || { 
    h2s: 0, methane: 0, motorCurrent: 0, tilt: {x:0,y:0,z:0}, timestamp: 0, battery: 100, isOffline: false 
  };

  const checkSafetyViolations = useCallback((data: SensorData) => {
    if (robotStatus.eStopActive) return true;

    const h2sViolated = !data.isOffline && data.h2s > safetyConfig.h2sLimit;
    const ch4Violated = !data.isOffline && data.methane > safetyConfig.methaneLimit;
    const currentViolated = data.motorCurrent > safetyConfig.maxCurrent;
    const tiltViolated = Math.abs(data.tilt.x) > safetyConfig.tiltLimit;
    const batteryViolated = data.battery < safetyConfig.batteryCritical;

    if (h2sViolated || ch4Violated || currentViolated || tiltViolated || batteryViolated) {
      if (!isOverriddenBySafety.current) {
        let reason = "Threshold Exceeded";
        if (batteryViolated) reason = "CRITICAL BATTERY";
        addLog(`SAFETY OVERRIDE: ${reason}. Forcing Recovery Mode.`, 'err');
        setRobotStatus(prev => ({ 
          ...prev, 
          direction: 'backward', 
          cleaning: false, 
          pumpActive: false 
        }));
        isOverriddenBySafety.current = true;
      }
      return true;
    }

    if (isOverriddenBySafety.current) {
      addLog("SAFETY STATUS: Levels normalized. AI control restored.", 'info');
      isOverriddenBySafety.current = false;
    }
    return false;
  }, [safetyConfig, robotStatus.eStopActive]);

  // Simulate or maintain sensor data stream
  useEffect(() => {
    const interval = setInterval(() => {
      setSensors(prev => {
        const last = prev[prev.length - 1] || { 
          h2s: 5, methane: 10, motorCurrent: 0.8, 
          tilt: {x: 0, y: 0, z: 9.8}, timestamp: Date.now(),
          battery: 85, isOffline: false
        };

        let newData: SensorData;

        if (isDemoMode) {
          // Slowly drain battery in cleaning mode
          const batteryDrain = robotStatus.cleaning ? 0.05 : 0.01;
          newData = {
            ...last,
            h2s: last.isOffline ? 0 : Math.max(0, last.h2s + (Math.random() - 0.5) * 0.1),
            methane: last.isOffline ? 0 : Math.max(0, last.methane + (Math.random() - 0.5) * 0.5),
            battery: Math.max(0, last.battery - batteryDrain),
            timestamp: Date.now()
          };
        } else {
          // Regular jitter simulation
          newData = {
            h2s: Math.max(0, last.h2s + (Math.random() - 0.5) * 0.5),
            methane: Math.max(0, last.methane + (Math.random() - 0.5) * 2),
            motorCurrent: robotStatus.cleaning ? 1.2 + (Math.random() - 0.5) * 0.4 : 0.8 + (Math.random() - 0.5) * 0.1,
            tilt: {
              x: last.tilt.x + (Math.random() - 0.5) * 0.1,
              y: last.tilt.y + (Math.random() - 0.5) * 0.1,
              z: 9.8 + (Math.random() - 0.5) * 0.2
            },
            battery: Math.max(0, last.battery - (robotStatus.cleaning ? 0.02 : 0.005)),
            timestamp: Date.now(),
            isOffline: false
          };
        }

        checkSafetyViolations(newData);
        return [...prev.slice(-19), newData];
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [isDemoMode, robotStatus.cleaning, checkSafetyViolations]);

  const handleCapture = async (base64: string) => {
    if (robotStatus.eStopActive) return;
    try {
      const result = await analyzeRobotState(base64, sensors);

      // Safety rule hierarchy: If we are in override, ignore AI movement suggestions
      if (isOverriddenBySafety.current) {
        setAiResult({
          ...result,
          recommendation: "⚠️ EMERGENCY PROTOCOL: " + result.recommendation
        });
      } else {
        setAiResult(result);
      }

      if (result.isStuck) {
        setLogs(prev => [{ msg: "ALERT: AI detected possible collision or stall!", type: 'warn' }, ...prev]);
      }
    } catch (err) {
      console.error("AI Analysis failed:", err);
    }
  };

  const addLog = (msg: string, type: 'info'|'warn'|'err' = 'info') => {
    setLogs(prev => [{ msg: `[${new Date().toLocaleTimeString()}] ${msg}`, type }, ...prev.slice(0, 49)]);
  };

  const handleCommand = (cmd: Partial<RobotStatus>) => {
    if (robotStatus.eStopActive) return;

    // Manual override check
    if (isOverriddenBySafety.current && (cmd.direction === 'forward' || cmd.direction === 'left' || cmd.direction === 'right')) {
      addLog("COMMAND BLOCKED: Safety protocol active. Only RETREAT allowed.", 'err');
      return;
    }

    setRobotStatus(prev => ({ ...prev, ...cmd }));
    if (cmd.direction) addLog(`Manual control: ${cmd.direction.toUpperCase()}`);
    if (cmd.cleaning !== undefined) addLog(`Manual toggle: Brush ${cmd.cleaning ? 'ON' : 'OFF'}`);
  };

  const toggleEStop = () => {
    setRobotStatus(prev => {
      const active = !prev.eStopActive;
      if (active) {
        addLog("!!! EMERGENCY STOP ACTIVATED !!!", 'err');
        return { ...prev, eStopActive: true, direction: 'stop', cleaning: false, pumpActive: false };
      } else {
        addLog("System reset. Safety check required.", 'info');
        return { ...prev, eStopActive: false };
      }
    });
  };

  const updateDemoSensors = (data: Partial<SensorData>) => {
    setSensors(prev => {
      const last = prev[prev.length - 1];
      const updated = { ...last, ...data, timestamp: Date.now() };
      return [...prev.slice(0, -1), updated];
    });
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-gray-950 font-sans selection:bg-emerald-500/30">
      <DashboardHeader 
        isConnected={robotStatus.connected} 
        isDemoMode={isDemoMode}
        eStopActive={robotStatus.eStopActive}
        onToggleDemo={() => setIsDemoMode(!isDemoMode)}
        onEStop={toggleEStop}
      />

      <main className="flex-1 flex overflow-hidden p-6 gap-6">
        {/* Left Side: Feed and Sensors */}
        <div className="flex-[2] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
          {isDemoMode && <DemoPanel currentSensors={latestSensor} onUpdate={updateDemoSensors} />}

          <CameraFeed onCapture={handleCapture} isSimulated={isDemoMode} />
          <SensorGrid data={latestSensor} gasRisk={aiResult.gasRisk} />

          <div className="bg-gray-900 border border-gray-800 rounded-xl p-6 flex-1 shadow-inner relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500/30"></div>
            <h3 className="text-sm font-bold uppercase text-gray-500 mb-4 flex justify-between items-center">
              <span>AI Intelligent Analysis</span>
              <span className="text-[10px] font-mono text-emerald-700">MODEL: GEMINI_3_FLASH</span>
            </h3>
            <div className="space-y-4">
              <div className="flex items-start space-x-4">
                <div className={`p-2 rounded-lg ${aiResult.isStuck || isOverriddenBySafety.current ? 'bg-red-900/40' : 'bg-emerald-900/40'}`}>
                   {aiResult.isStuck || isOverriddenBySafety.current ? (
                     <svg className="w-6 h-6 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                   ) : (
                     <svg className="w-6 h-6 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                   )}
                </div>
                <div>
                  <h4 className="font-bold text-gray-200 flex items-center">
                    Control Recommendation
                    {isOverriddenBySafety.current && <span className="ml-2 text-[10px] bg-red-600 px-1 rounded text-white animate-pulse">OVERRIDDEN</span>}
                  </h4>
                  <p className="text-gray-400 text-sm leading-relaxed mt-1 italic">
                    "{aiResult.recommendation}"
                  </p>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 mt-6">
                <div className="bg-gray-800/40 p-4 rounded-lg border border-gray-700/50">
                  <span className="text-[10px] text-gray-500 font-bold uppercase block mb-1">Visual Density</span>
                  <span className={`text-lg font-bold ${
                    aiResult.sludgeLevel === SludgeLevel.HEAVY ? 'text-red-400' :
                    aiResult.sludgeLevel === SludgeLevel.MEDIUM ? 'text-amber-400' :
                    'text-emerald-400'
                  }`}>{aiResult.sludgeLevel}</span>
                </div>
                <div className="bg-gray-800/40 p-4 rounded-lg border border-gray-700/50">
                  <span className="text-[10px] text-gray-500 font-bold uppercase block mb-1">Optimum Target</span>
                  <span className="text-lg font-bold text-blue-400 uppercase tracking-tighter">{aiResult.targetZone || 'SCANNING...'}</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right Side: Controls and Logs */}
        <div className="flex-1 flex flex-col gap-6 max-w-sm">
          <SafetyStatus 
            data={latestSensor} 
            config={safetyConfig} 
            isOverridden={isOverriddenBySafety.current}
            eStopActive={robotStatus.eStopActive}
          />

          <div className={`${robotStatus.eStopActive ? 'opacity-40 grayscale pointer-events-none' : ''} transition-all`}>
            <RobotControls status={robotStatus} onCommand={handleCommand} />
          </div>

          <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 flex-1 flex flex-col shadow-inner overflow-hidden">
            <h3 className="text-[10px] font-bold uppercase text-gray-600 mb-3 tracking-widest flex justify-between">
              <span>Mission Telemetry</span>
              <button onClick={() => setLogs([])} className="hover:text-gray-400">CLEAR</button>
            </h3>
            <div className="flex-1 overflow-y-auto font-mono text-[10px] space-y-1.5 pr-2 custom-scrollbar">
              {logs.length === 0 && <div className="text-gray-800 italic mt-4 text-center">Awaiting log initiation...</div>}
              {logs.map((log, i) => (
                <div key={i} className={`p-1.5 rounded border-l-2 ${
                  log.type === 'err' ? 'bg-red-900/10 border-red-500 text-red-300' :
                  log.type === 'warn' ? 'bg-amber-900/10 border-amber-500 text-amber-300' :
                  'bg-gray-800/30 border-gray-700 text-gray-500'
                }`}>
                  {log.msg}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="bg-gray-900 border-t border-gray-800 px-6 py-2 text-[10px] text-gray-600 flex justify-between items-center">
        <div className="flex space-x-6 items-center">
          <span className="flex items-center"><span className="w-1.5 h-1.5 rounded-full bg-emerald-500 mr-2"></span>GPS: 12.971°N 77.594°E</span>
          <span className="flex items-center"><span className="w-1.5 h-1.5 rounded-full bg-gray-500 mr-2"></span>LINK: 5.8GHz / AES-256</span>
          <span className="bg-gray-800 px-2 py-0.5 rounded text-gray-400">ESP32_STP_V3.1</span>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex space-x-1">
             {[...Array(5)].map((_, i) => <div key={i} className={`w-1 h-3 rounded-full ${i < 4 ? 'bg-emerald-800' : 'bg-gray-800'}`}></div>)}
          </div>
          <span className="uppercase font-bold tracking-[0.2em] text-gray-700">Project SludgeForce</span>
        </div>
      </footer>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #374151;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #4b5563;
        }
      `}} />
    </div>
  );
};

export default App;

import React from 'react';
import { SensorData } from '../types';

interface AnalyticsDashboardProps {
  sensors: SensorData[];
}

const TrendLine: React.FC<{ 
  data: number[]; 
  color: string; 
  label: string; 
  height?: number;
  minVal?: number;
  maxVal?: number;
}> = ({ data, color, label, height = 60, minVal, maxVal }) => {
  if (data.length < 2) return null;

  const min = minVal !== undefined ? minVal : Math.min(...data);
  const max = maxVal !== undefined ? maxVal : Math.max(...data);
  const range = max - min || 1;

  const points = data.map((val, i) => {
    const x = (i / (data.length - 1)) * 100;
    const y = 100 - ((val - min) / range) * 100;
    return `${x},${y}`;
  }).join(' ');

  return (
    <div className="flex flex-col flex-1">
      <div className="flex justify-between items-end mb-1">
        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-tighter">{label}</span>
        <span className={`text-[10px] font-mono ${color}`}>{data[data.length - 1].toFixed(1)}</span>
      </div>
      <div className="relative bg-gray-900/50 rounded border border-gray-800/50 p-1 overflow-hidden" style={{ height }}>
        <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="w-full h-full">
          <polyline
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            points={points}
            className={color}
          />
          {/* Subtle area fill */}
          <polyline
            fill="currentColor"
            fillOpacity="0.05"
            points={`0,100 ${points} 100,100`}
            className={color}
          />
        </svg>
      </div>
    </div>
  );
};

