            timestamp: Date.now(),
            isOffline: false
          };
        }

        checkSafetyViolations(newData);
        // Keep 60 seconds of history for charts
        return [...prev.slice(-59), newData];
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [isDemoMode, robotStatus.cleaning, checkSafetyViolations]);

